const body = $json.body ?? $json;
const traceId = body.traceId || body.jobId || `trace-${Date.now()}`;
const userText = String(body.userText || '').trim();
const messages = Array.isArray(body.messages) ? body.messages : [];
return [{ json: {
  traceId,
  workflowId: body.workflowId || '6KFFgjd26nF0kNCA',
  requestedByWorkflowId: '6KFFgjd26nF0kNCA',
  roomId: body.roomId || null,
  jobId: body.jobId || null,
  deviceId: body.deviceId || null,
  userText,
  messages,
  action: body.action || null,
  params: body.params || null
}}];

const root = $json.body ?? $json;
const raw = root?.choices?.[0]?.message?.content || root?.replyText || root?.text || '';
let parsed = {};
if (typeof raw === 'string') {
  try {
    parsed = JSON.parse(raw);
  } catch {
    parsed = {};
  }
}
const prev = $('Normalize Input').item.json;
const fallbackNeed = /^tool:|^api:|menu|price|availability|order|status|db|database/i.test(prev.userText || '');
const requiresMcp = typeof parsed.requiresMcp === 'boolean' ? parsed.requiresMcp : fallbackNeed;
const intent = String(parsed.intent || 'general_query');
const action = String(parsed.action || (requiresMcp ? 'database.question' : 'none'));
const query = String(parsed.query || prev.userText || '');
const ask = String(parsed.ask || '');
return [{ json: { ...prev, intent, requiresMcp, action, query, ask, intentRaw: raw } }];

const hasMcp = $input.item.pairedItem?.input === 0 || !!$json.ok || !!$json.data || !!$json.error;
if (hasMcp && ('ok' in $json || 'data' in $json || 'error' in $json)) {
  const base = $('Parse Intent').item.json;
  return [{ json: { ...base, mcp: { ok: Boolean($json.ok), status: Number($json.status || 0), data: $json.data ?? null, error: $json.error ?? null, durationMs: $json.durationMs ?? null } } }];
}
return [{ json: { ...$json, mcp: null } }];

