const rawRoot = $json.body ?? $json;
const llmText = String(rawRoot?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Merge Context').item.json;
const fallback = ctx.ask || (ctx.mcp && ctx.mcp.ok === false ? 'I could not fetch that data now. Please try again.' : 'How can I help you?');
const replyText = llmText || fallback;
return [{ json: { replyText, meta: { intent: ctx.intent, requiresMcp: ctx.requiresMcp, mcp: ctx.mcp, traceId: ctx.traceId } } }];
